record.field:
[
  {
    "type": "system",
    "content": {{ ('You are a ' + role + '.

Your goal is to ' + goal + '

Background: ' + background + '

Instructions:
' + instructions + '

' + footer) | tojson }}
  },
  {
    "type": "user",
    "content": {{ ('Extract invoice data from the following OCR text and return ONLY the JSON object, no explanations or markdown:

' + ocr_text) | tojson }}
  }
]

{
            "role": {
                "type": "string",
                "description": "The role of the assistant",
                "required": true
            },
            "goal": {
                "type": "string",
                "description": "The primary goal",
                "required": true
            },
            "background": {
                "type": "string",
                "description": "Background information",
                "required": true
            },
            "instructions": {
                "type": "string",
                "description": "Specific extraction instructions",
                "required": true
            },
            "footer": {
                "type": "string",
                "description": "Optional footer",
                "required": false,
                "default": ""
            },
            "ocr_text": {
                "type": "string",
                "description": "OCR extracted text from invoice (injected via dynamic defaults)",
                "required": true
            }
        }
